INSERT INTO `bd_customer` VALUES (7, 100963, 'SA222', 'MPCS', 'C', 'BRAM', '', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:47', '2026-01-28 18:41:48', NULL, NULL, '612de03b8c1ff8', '612de03b8c1ff8', ' ', 'Ramshoorn 2 4824 AG  Breda', NULL, '076-205 2002', NULL, 'https://www.mp-cs.nl/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168248', ' ', '', '', '自 2006 年成立以来，我们专注于设计和实施简单的电缆组件，包括最复杂的电缆线束。我们在生产各种形状和尺寸的螺旋电缆方面也拥有丰富的知识。', '线束、保险丝盒、电缆组件、螺旋电缆、光纤、数据布线、', NULL, NULL, NULL, '1', 0, '1，蓝色塑盒，中性包装，质量要好，交期要快。出荷兰，满足荷兰要求。', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 39.47, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (8, 100964, 'SA217', 'Tuffline Power Sports', 'C', 'Tuff', 'Tuffline Power Sports', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:47', '2026-01-28 18:41:48', NULL, NULL, '60ed5247db746f', '60ed5247db746f', ' ', 'BOX 239, 10202 - 100 Street LA CRETE, AB T0H 2H0', NULL, '(780) 928-3932', NULL, 'https://www.tuffline.com/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168248', ' ', '', '', '我们自 1978 年以来一直在本地拥有和经营。那是 25 年以上致力于提供卓越的客户服务。除了携带您最喜欢的 Polaris 雪地摩托和 ATV，我们还提供多种配件和零件，让您的骑行更加愉快。查看我们的服务部门。我们为大多数品牌和型号的 ATV、雪地摩托和小型发动机提供服务。我们的服务技术人员将正确有效地服务或维修您的产品。Tuffline 的服务值得您信赖。让 Tuffline Power Sports 成为您的一站式娱乐商店！\n\n\n\nTuffline Power Sports 提供全系列的斯蒂尔电动工具和配件。我们是获授权的 Briggs & Stratton、Tecumseh、Kohler 和 Honda 发动机服务中心。', '割草机、雪地摩托', NULL, NULL, NULL, '1', 0, '中性包装', '1', '', '', NULL, NULL, NULL, NULL, 10.00, '', 0, 35.07, '', '', ' ', '', '', 'https://www.facebook.com/tufflinepowersports', '', 'https://www.instagram.com/tuffline_powersports/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
