INSERT INTO `bd_customer` VALUES (11, 100967, 'BR252', 'Jack Hu', 'C', 'Jack Hu', '', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100949, '', 100100, 0, '2021-02-23 17:33:47', '2026-01-28 18:41:48', NULL, NULL, '46a524cf-5797-4e46-bd0a-7203fc426d9c', '46a524cf-5797-4e46-bd0a-7203fc426d9c', ' ', ' ', NULL, '13249628018', NULL, ' ', 1, '0', 0, 0, 127128, NULL, 234.00, NULL, 100070, '168248', ' ', '', '', '', '', NULL, NULL, NULL, '1', 0, '1.大货产品的质量要和之前提供的样品的质量一模一样                                                            \n\n2.打气筒的颜色变为银色(如下图),压力表单位更换(如下图),其余的和之前样品保持一致，包括质量和材料务必一致          \n\n3.产品必须符合欧盟的Reach标准,原料必须使用环保材料(如有证书请提供)          \n\n4.包装物料必须使用环保材料,禁止任何材料使用PVC          \n\n5.包装要按照20pc一箱，不需要pp袋，五个或四个一排，每个产品之间要有小纸板相隔，每层和每层之间要有小纸板相隔，小纸板材料可以和包装纸箱材料一致。          \n\n6.包装的产品必须是完好的整个产品，不能各个部件拆分了放，需要完整的产品直接放入          \n\n7.交期一定要准时，只能提前完成，不能延迟          \n\n8.交货时需要提供产品的CE认证复印件          \n\n9.大货产品客户需要留底检测，所以工厂在生产过程中需要多生产3套产品，相当于需要生产数量是3003套，请理解          \n\n10.产品上边需要有彩贴（彩贴我司提供设计稿，供方负责制作包装）          \n\n11.需要有唛头信息（待定，唛头由工厂印刷或者贴）          \n\n12.产品需要有使用说明书          \n\n13.产品所有的材料务必务必是环保材料，禁止任何地方的材料使用PVC          \n\n14.需要绑一个标签（标签我司提供）', '1', '', '', NULL, 2, 1, NULL, 10.00, '', 0, 13.51, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
