INSERT INTO `bd_customer` VALUES (13, 100969, 'SA213', 'FULLthrottle', 'C', 'FULL', 'FULLthrottle', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:47', '2026-01-28 18:41:48', NULL, NULL, 'f98a3ac14f0b4397a332b2353f1fc66c', 'f98a3ac14f0b4397a332b2353f1fc66c', ' ', '1010 34TH AVE|COUNCIL BLUFFS, IA 51501', NULL, '712.366.8400；712.458.3390；712.430.0733；712.430.0722', NULL, 'https://www.edwardsmotorsports.com/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168248', ' ', '', '', 'Edwards Motorsports 是位于爱荷华州康瑟尔布拉夫斯的 Honda®、Husqvarna、Kawasaki、Polaris® 和 Suzuki powersport 授权经销商。除了大量新型号的全地形车、摩托车/踏板车、私人船只、雪地摩托和多功能车外，Edwards Motorsports 还提供各种二手型号。\n\n\n\nEdwards Motorsports 提供卓越的客户服务，并拥有一个由专业销售人员、财务专家、服务技术人员和知识渊博的零件和配件人员组成的完整团队来为您提供支持。我们为拥有训练有素的专家而自豪，他们致力于让客户满意。Edwards Motorsports 是位于爱荷华州康瑟尔布拉夫斯的 E-Ton、Honda®、Husqvarna、Kawasaki、Yamaha、Can-Am®、Spyder®、Sea-Doo®、Polaris®、Suzuki Powersports 和 Beta Motorcycles 的授权经销商。', '全地形车、摩托车/踏板车、私人船只，和多功能车，Edwards Motorsports 提供各种二手车型。', NULL, NULL, NULL, '1', 0, '中性包装', '1', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/channel/UCiWal95oIVHBxQsDnA90LEA', 'https://www.linkedin.com/company/edwards-motorsports/about/', 'https://www.facebook.com/FullThrottleFans', '', 'https://www.instagram.com/edwardsmotorsport/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
