INSERT INTO `bd_customer` VALUES (30, 100986, 'SA111', 'Triumf professional tools s.r.o.', 'C', 'Triumf', 'Triumf professional tools s.r.o.', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:48', '2026-01-28 18:41:48', NULL, NULL, '6152b65f5e864d', '6152b65f5e864d', ' ', 'Kollárova 88\n\n036 01 Martin', NULL, '043 4003 612，043 4003 613', NULL, 'https://www.triumftools.sk/', 7, '0', 0, 0, 127241, NULL, 234.00, NULL, 100070, '168254', ' ', '', '', '公司成立于 1999 年\n\n该公司目前在斯洛伐克有 10 名汽车服务和轮胎服务业务的销售代表，4 名手动工具商店的销售代表。在捷克共和国，该公司提供了一个由 4 个销售代表组成的网络，用于销售网络和 5 个汽车服务业务代表。在波兰，一名销售代表和一名汽车维修技术员。', '工具展示架 (57)\n\n工具车和工作台 (131)\n\n3 - 钥匙 (177)\n\n钥匙 (177)\n\nGola 套装、组合套装 (235)\n\nGola 套装、组合套装(235)\n\n特殊车头 (98)\n\n棘轮、木椅、延长件 (116)\n\n扭矩扳手、倍增器 (23)\n\n锻造工具 (168)\n\n螺丝刀钻头和套件。(185)\n\n螺丝刀 (255)\n\n钳子 (275)\n\n折刀、刀片、镊子 (69)\n\n锤子、锯子、仪表、凿子、锉刀 (180)\n\n钻头 (116)\n\n水龙头 (110)\n\n虎钳和刀具 (15)\n\n刀片、锯子、刷子 (46)\n\n灯 (55)\n\n家用工具 (288)\n\n气动工具 (185)\n\n检查和自动电动工具 (175)拉拔器、撬棍、压力机(92)\n\n汽车 - 拉马 (249)\n\nWallmek - 底盘技术 (254)\n\n油品管理 (191)\n\n排气管 (28)\n\n发动机工具 (71)\n\n专业的胜利（170）\n\n电热塞 (244)\n\n喷油器 (405)\n\nDieselLand - 共轨系统\n\n刹车和离合器工具 (202)\n\n分配锁定套件 (253)\n\n袖口和配件 (38)\n\n燃料、冷却、空气和空调系统。(242)\n\n轮胎维修工具 (104)\n\n千斤顶、支架 (30)\n\n汽车玻璃工具 (114)\n\n汽车工具 (239)\n\n塑料焊接 (97)\n\n保护和卫生 (21)\n\n凯旋新闻 (67)\n\n凯旋配件 (260)', NULL, NULL, NULL, '1', 0, '有定牌插卡。有中性包装+彩贴看产品', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 18.11, '', '', ' ', 'https://www.youtube.com/channel/UCqdAMac7aHfB796di8IrcBw', '', 'https://www.facebook.com/Triumf-TOOLS-977508508958496/', '', 'https://www.instagram.com/triumftools/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
