INSERT INTO `bd_customer` VALUES (32, 100988, 'SA200', 'SP TOOLS LIMITED', 'C', 'SP-上海', 'sptools', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-02-23 17:33:49', '2026-01-29 08:40:09', NULL, NULL, '60e7ba25d450c8', '60e7ba25d450c8', ' ', '23 Iris Place, Acacia Ridge, QLD, 4110.', NULL, '1300 4 667747', NULL, 'https://www.sptools.com/', 7, '0', 0, 309585, 127249, NULL, 234.00, NULL, 100070, '168251', ' ', '', '', 'SP Tools 和 SP Air 在 30 个国家/地区拥有 40 多个国际代理商，其中包括多家公司拥有和运营的办事处。近 40 年来，SP 一直处于设计和制造的前沿。', '冲击套筒、六角和梅花、工具包、扳手 移位器、钳子 刀具、专业工具 车间 照明、压缩机、无绳工具、发电机、插座 配件、螺丝刀 钻头套装、敲击 切割 紧固工具、气动工具、高压清洗机。范围涵盖气动工具、电动工具、手动工具、汽车专业工具、车库设备、空气压缩机和其他相关产品。', NULL, NULL, NULL, '1', 0, '1,定牌泡壳插卡，提供刀模，客人设计 2，产品细节：2.5“ 表，0-300psi,0-21kg/cm2  3,产品上面要打LOGO,如图(打印LOGO之前，先打一个样品给客户确信，客户确认后再打大货LOGO）：    质量要好，交期要快，符合澳洲市场。4,先内箱装，后外箱装，一个外箱不超过20kg .内箱根外箱要贴条形码，连个条形码是不一样的。内箱条形码跟外箱条形码不一样，但是都可以贴也可以印。外箱上面的警示图片根据重量的不同而不同。\n\n不同产品不同的包装。要注意下', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 7, 27.97, '', '', ' ', 'https://www.youtube.com/channel/UCXXSCgIcrHLoWj2eHr_f0cg', 'https://www.linkedin.com/company/sp-tools-australia/', 'https://www.facebook.com/sphandtools', 'https://twitter.com/sptoolsracing', 'https://www.instagram.com/sptools/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
