INSERT INTO `bd_customer` VALUES (42, 100998, 'SI149', 'KS TOOLS', 'C', 'KS TOOLS', '', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:49', '2026-01-28 18:41:48', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', 'Seligenstädter Grund 10-12 63150 Heusenstamm', NULL, ' ', NULL, 'https://www.kstools.com/', 7, '0', 0, 0, 151872, NULL, 234.00, NULL, 100069, '168250', ' ', '', '', '全球 9 家分公司的 350 多名员工;公司目前出口到世界上超过 135 个国家;我们是国际上成功的工具品牌，在汽车（机动车辆/商用车）、工业和卫生、供暖和空调领域的手动工具领域拥有超过 35,000 种创新产品。对于全面的产品系列，我们目前在 Heusenstamm 的中央仓库拥有总面积为 10,330 平方米、高度为 8 米的仓库。近 8,865 个托盘和 8,100 个小零件存储箱永久放置在这里。', 'Hand tools catalogue;\n\nSpecial tools for passenger cars and light commercial vans;\n\nSpecial tools for commercial vehicle;\n\nSpare parts;\n\nClip-Finder;\n\nTool-Finder;\n\nFan shop', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 29.91, '', '', ' ', 'https://www.youtube.com/user/KSTOOLSTOOLCHANNEL/featured', 'https://www.linkedin.com/company/ks-tools-werkzeuge-maschinen-gmbh/', 'https://www.facebook.com/kstools/', 'https://twitter.com/kstools_com', 'https://www.instagram.com/kstools_com/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (43, 100999, 'SA249', 'sculeauto', 'C', 'IVA', 'sculeauto', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-02-23 17:33:50', '2026-01-29 08:40:09', NULL, NULL, '60a36bd2301873', '60a36bd2301873', ' ', 'RO18612231 N.Balcescu Nr:8 , Bl:B2 , Sc:E,Ap:5   300236 TIMISOARA\n\n                   ROMANIA', NULL, '0735848636', NULL, 'https://www.sculeauto.ro/', 7, '0', 0, 309524, 127254, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', '自 2000 年以来拥有销售经验的 IVASCO 公司的业务领域不仅是进口和分销用于自助服务的手动工具和顶级专业设备。我们在东欧、罗马尼亚、保加利亚、南斯拉夫、匈牙利、共和国独家代理 StahlRhein 品牌产品、手动工具和自助服务设备。摩尔多瓦和乌克兰。我们还是罗马尼亚 Technolit、Pennasol 的唯一授权进口商，以及 Matador、Rohrlux、Friedrich 和 BGS Technic 品牌的直接进口商。所有这些公司都符合罗马尼亚市场目前在该领域施加的质量、价格和保证条件。', '手动工具\n\nTINICHIGERIE, VOPSITORIE\n\n硫化\n\n电梯、升降系统\n\n压缩机\n\n气动工具\n\n车间设备\n\n诊断、气候装置\n\n化学耗材\n\n发电机、热风机\n\n配饰\n\n胶水和焊接设备\n\n灯/灯笼服务', NULL, NULL, NULL, '1', 0, '蓝色（蓝色300C）铁盒装.铁盒上贴彩贴+热收缩。', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 8.19, '', '', ' ', '', '', 'https://www.facebook.com/StahlRheinRomania/?ref=pages_you_manage', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (44, 101000, 'ET134', 'MSA International S.A.', 'C', 'MSA', 'MSA International S.A.', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 238073, '徐文科、李巧玲', 100098, 0, '2021-02-23 17:33:50', '2026-01-28 18:41:48', NULL, NULL, '61161d2928d9a0', '61161d2928d9a0', ' ', 'PED\n\nAvenue de l\'Europe\n\nL-4802 LAMADELAINE\n\nLUXEMBOURG', NULL, ' ', NULL, 'http://www.msainternational.com', 1, '0', 0, 0, 127154, NULL, 234.00, NULL, 100069, '168246', ' ', '', '贸易商', '在 LinkedIn有16 个员工', '设备 工具', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 3.00, '', 28, 21.36, '1996 年以来，MSA International 一直在法国、比利时和卢森堡分销配件，MSA International 不断开发其用于踏板车、摩托车和四轮摩托车手的设备系列、适合在城市和越野环境中使用机动车辆的设备，以及供专业人士和个人使用的手动工具和车间工具', '', ' ', 'https://www.youtube.com/channel/UC_a2K5B5kD_CCdxNi38rQIg', 'https://www.linkedin.com/company/msa-international/about/', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
