INSERT INTO `bd_customer` VALUES (59, 101015, 'S00020', 'JOMA IMPORT&EXPORT SL', 'C', 'JT', 'ECD  Germany', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-02-23 17:33:51', '2026-01-28 18:41:48', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', '45 Höhenweg, Wiehl, Germany', NULL, '+49 2247 9168371', NULL, 'http://www.ecdgermany.de/', 7, '0', 0, 0, 127214, NULL, 234.00, NULL, 100070, '168254', ' ', '', '', '我们公司自 1990 年以来已成功代表零售业，并自 2002 年起在网上交易中取得成功。从镀铬轮拱和用于汽车调整的木制内饰开始，\n\n在有限的范围内，主要是在本地，只有少数员工，现在是一家不断发展的中型\n\n零售公司，客户遍布欧洲。\n\n每天大约有 3000 个包裹发货，我们是在线交易领域的老牌玩家。', '产品范围包括超过一万个项目，并分为三大产品类别。汽车零配件和工具、\n\n电子产品和照明以及家庭和生活领域。', NULL, NULL, NULL, '1', 0, '不要包装的JT买塑盒是要加彩套的\n\n一箱不能超过18kg产品上贴客人贴纸.再用坚硬的内盒包装（不能用软的薄的），内盒外面贴2张贴纸。几套入一个外箱。请注意唛头格式。（唛头需跟我司确认方可制作.若无确认，我司概不负责）出口德国质量需符合德国标准.德式接头。', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 13.90, '', '', ' ', 'https://www.youtube.com/channel/UCG4IL-RJS3C1HiC3op7ytfg', 'https://www.linkedin.com/company/eris-car-design-gmbh/', 'https://www.facebook.com/ECD.Germany', 'https://twitter.com/ECD_Germany', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (60, 101016, 'S00022', 'COGEX', 'C', 'TURBOCAR', 'TURBOCAR', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-02-23 17:33:51', '2026-01-29 08:40:09', NULL, NULL, '60e80e18d459f6', '60e80e18d459f6', ' ', 'Avenue de Paris, Fleurance, France 32500, FR', NULL, ' ', NULL, 'https://www.cogex.com/', 7, '0', 0, 309524, 153268, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', 'COGEX 的历史始于 1979 年\n\n它拥有 200 名员工，如今已成为 Gers 的主要雇主之一', '手动和电动工具\n\n机械工具\n\n电\n\n牵引和信号\n\n车间工具\n\nDIY、工具、电力、花园、户外、部门娱乐、汽车/摩托车、自行车和运动', NULL, NULL, NULL, '1', 0, '1,我们提供塑料吊卡，包装 2，塑料吊卡后面贴一个不干胶，不干胶我们提供。3，外面在用PP袋包一下\n\n1，先用内箱装，然后在几个内箱装一个外箱，一个外箱总重量不超过15kg.', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 56, 18.14, '', '', ' ', '', 'https://www.linkedin.com/company/cogex/posts/?feedView=all', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (61, 101017, 'AL017', 'SUNTEC INTERNATIONAL GROUP CO., LTD', 'C', 'SUNTEC 台灣泰錠', 'SUNTEC INTERNATIONAL GROUP CO., LTD.', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100949, '冯序', 100100, 0, '2021-02-23 17:33:51', '2026-01-28 18:41:48', NULL, NULL, '60f24bf02dae22', '60e7d426d45477', ' ', '1F, No.6, Aly. 21, Ln. 265, Gaogong Rd., South Dist., Taichung City 402, Taiwan (R.O.C.)', NULL, '886-4-22613001', NULL, 'suntec-tools.com', 7, '0', 0, 0, 127121, NULL, 234.00, NULL, 100070, '168248', ' ', '', '贸易公司', '', '电动 ，手动 ，气动， 套筒，汽修，工具车', NULL, NULL, NULL, '1', 0, '每個機油格貼上(商標+code+size)貼紙,要用客戶指定code和size樣式\n\n2.插卡+泡殼包裝,彩卡正面右上角要貼CODE貼紙\n\n3.每10pcs入1個中盒(瓦楞盒或白盒皆可),盒上需有下列內容(做貼紙或直接印上皆可)', '2', '', '', NULL, NULL, 1, NULL, 3.00, '', 12, 27.64, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
