INSERT INTO `bd_customer` VALUES (64, 101031, 'RO627', 'naradi-gesta.cz', 'C', 'STAH', 'naradi-gesta.cz', '找出来2个网站 2个地址 +421 /(0)918 / 467 095\n\n+421 /(0)908 / 212 125', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 229982, '罗元标', 100098, 0, '2021-02-23 17:47:01', '2026-01-29 08:40:09', NULL, NULL, '614c41d78d9f5a', '614c41d78d9f5a', ' ', 'Pouchovská 1272 500 03 Hradec Králové ；\n\nDvorská cesta 23 940 57 Nové Zámky；\n\nRožňavská 4588/24 821 04 Bratislava', NULL, '+420 608 832 027 ;+420 608 118 400', NULL, 'naradi-gesta.cz；https://www.stahlmann.sk/', 7, '0', 0, 309261, 0, NULL, 234.00, NULL, 100070, '168246', ' ', '', '', '自1992年以来，我们一直是捷克共和国德国手动工具厂GEDORE的合作伙伴。2012 年，我们的产品系列中还包括 STAHLMANN 手动工具。\n\n\n\n今天，GEDORE 品牌涵盖了 RAHSOL、TORQUELEDAR、LOSOMAT、HABERO、OCHSENKOPF 和 KLANN 品牌的工具。自 1992 年以来，我们一直是GEDORE在捷克共和国的合作伙伴。我们在广泛的GEDORE工具方面的经验是为您提供最佳服务的保证。\n\n\n\n我们提供服务GEDORE扭矩扳手和其他测量工具。杰多品牌的手动工具意味着高品质、性能可靠和使用安全。2018年以来，基多集团拥有两条产品线：歌多蓝 和 歌朵红. 该组还包括顶级林业工具奥森科普夫.', '套筒工具、扳手 棘轮扳手套装、钳子套装、螺丝刀、车间LED灯、工具车、VDE工具、汽车专业工具、拉马、弯管系统、林业工具、', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, NULL, NULL, 3.00, '', 0, 13.16, '', '', ' ', 'https://www.youtube.com/channel/UCBNZMlFHK4AFeY3LB14QI5g', '', 'https://www.facebook.com/stahlmanntools/', '', 'https://www.instagram.com/stahlmann_slovakia/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
