INSERT INTO `bd_customer` VALUES (86, 101053, 'VI067', 'LLC GROUP', 'C', 'RRG', 'ООО Группа Ремакс', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100952, '', 100099, 0, '2021-02-23 17:47:03', '2026-01-29 08:43:25', NULL, NULL, '60e7f9e3d4592a', '60e7f9e3d4592a', ' ', '620026 г. Екатеринбург, ул. Бажова, д. 193', NULL, '8 (343) 288-7-000   8 800 222 86 16', NULL, 'www.rossvik-shop.ru', 1, '0', 0, 309587, 127319, NULL, 234.00, NULL, 100068, '168250', ' ', '', '线上销售，有面向整个俄罗斯的全部销售网络（连锁线下店）', '', '汽车服务设备（轮胎修补材料\n\n诊断设备\n\n汽车升降机\n\n高压清洗机\n\n硫化机\n\n平衡机\n\n轮胎拆装机\n\n传输架\n\n汽车化学品）\n\n汽车服务工具（手动，气动，电动工具）', NULL, NULL, NULL, '1', 0, '唛头根据要求，正侧唛各贴两面。\n\n大货前一定要先确认\n\n1，外箱装箱资料与实际相差不得超过0.5.每款产品整箱装配，如出现零数箱需告知我司进行调整。\n\n2，不得漏发，错发，产品配件必须完整 完整 完整\n\n3，质量要与上次一致,唛头上面有条码的 务必保证条码能扫的出来\n\n4，彩贴与唛头相关的日期必须跟实际出货一致 2021.07\n\n5，装箱数与条码有关，老产品返单的不能更改 与之前出货的装箱数一样，新产品的装箱数/彩贴尺寸给我 客户自己设计，塑盒装配的产品彩贴尺寸要完全符合凹槽处尺寸。不得偏大偏小。\n\n6：每款产品需提供出货照，确认无误后安排发货。\n\n7：每款产品的质量要求要注意品质把控。', '2', '', '', NULL, 1, 1, NULL, 10.00, '', 10, 20.76, '该公司成立于 1996 年，由一家轮胎焊接公司和一个轮胎商店网络合并而成', '', ' ', 'https://www.youtube.com/c/holdingrossvik', '', '', '', 'https://www.instagram.com/rossvik_ural', 'https://vk.com/holding_rossvik', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (87, 101054, 'VI064', 'AUDE CONFORT THERMIQUE', 'C', 'ACT', 'Aude Confort Thermique sarl', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100952, '', 100099, 0, '2021-02-23 17:47:03', '2026-01-28 18:41:48', NULL, NULL, '60e80e18d459f6', '60e80e18d459f6', ' ', '15 Chemin de Ronde\n\n11300 - Limoux - France', NULL, '+33(0)9 53 38 66 98', NULL, 'www.toolseurodiscount.com', 1, '0', 0, 0, 127317, NULL, 234.00, NULL, 100070, '168244', ' ', '', '线上销售', '', '制冷设备工具与配件\n\n空调相关配件与保养\n\n通用工具和汽车工具', NULL, NULL, NULL, '1', 0, '一、限重要求，一个外箱不能超过20公斤\n\n二、纸箱要求：常规现在是5层，\n\n三、外箱打打包带要求：一定要打打包带井字形4根', '2', '', '', NULL, 2, 1, NULL, 10.00, '', 0, 18.79, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (88, 101055, 'VI063', 'GONSER AG', 'C', 'GIT', 'GONSER AG', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100952, '', 100099, 0, '2021-02-23 17:47:03', '2026-01-29 08:40:09', NULL, NULL, '60e80a3ad459f4', '60e80a3ad459f4', ' ', 'Bahnhofstrasse 4\n\nHorw​, LUZERN, 6048\n\nSwitzerland', NULL, ' ', NULL, 'www.gonser.ch', 7, '0', 0, 309585, 127316, NULL, 234.00, NULL, 100070, '168254', ' ', '', '线上销售', '', '户外，家居，母婴，宠物，园林，汽修工具，电动工具等', NULL, NULL, NULL, '1', 0, '1. 包装未有变动，需要彩贴的彩贴依然原来的设计\n\n2. 新产品，出货前客户需要我们这边提供高清抠好的图片放在网站上面\n\n3. 纸箱要求：常规现在是5层\n\n4. 外箱打打包带要求：打包带 打的形状为井字形\n\n5. 胶带工字型封箱\n\n6. 唛头四面增加了条码\n\n7. 老客户如果换供应商要提供给我所有的对比图，如若不提供对比图，出现任何问题业务概不负责 采购全责。', '2', '', '多套一箱不需要外箱条码，因为多套一箱是要彩贴 上面带条码的，如果多套一箱带条码，条码仓库发货会整箱发走那种 不看数字的', NULL, NULL, 1, NULL, 10.00, '', 54, 20.64, '', '', ' ', '', '', '', '', 'https://www.instagram.com/gonser.ch/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
