INSERT INTO `bd_customer` VALUES (93, 101060, 'VI026-1', '迦祺贸易股份有限公司', 'C', '迦祺贸易-波兰', '迦祺贸易股份有限公司', '\"Ооо Айкартул  Russia   31次交易  这个买家2020/1出货21次，2020/2 6次，2020/4月 24次，2020/5 2次，2020/6 6次，2020/7  3次，2020/8 34次，2020/9 13次，2020/10 2次 和dicong 有合作，/https://www.autoscaners.ru/ \nDistribution International Southwes    United States  15次交易/ https://www.distrib', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100952, '', 100099, 0, '2021-02-23 17:47:04', '2026-01-28 18:41:48', NULL, NULL, '60e7d9f3d454c8', '60e7d9f3d454c8', ' ', '台湾 台中市南屯区永顺路558号', NULL, ' ', NULL, 'ellientools.com', 7, '0', 0, 309585, 152050, NULL, 234.00, NULL, 100068, '168254', ' ', '', '贸易公司', '徐儷澄/注册资本10,000,000/1995-6-29 注册', '汽车专用工具\n\n汽保工具\n\n手工具\n\n表类\n\n大车工具\n\n油交换机\n\n扭力扳手\n\n气动风炮扳手\n\n工作灯', NULL, NULL, NULL, '1', 0, '一、限重要求：一个外箱不能超过多少20公斤\n\n二、纸箱要求：常规现在是5层，特殊要求要注明。\n\n三、外箱打打包带打4根井字形，封箱工字型\n\n四、要跟之前品质一样，不一样，后果自负', '2', '', '一定要打打包带，不打打包带，就要打托！！！\n\n關於我們波蘭客户，因為现在訂軍數量较多，出貨產品需要你配合以下幾件事:\n1.出貨產品 一定要與送樣產品相同(連內模也不可以改變)不論是更换工廠 或是更换內模，全部都要在出貨前通知我司，且重新送樣後確認，才可以出貨2.吹氣盒顏色:波蘭客戶只接受“红色\"或“黑色”，我們已經有下單至100的数量而且反覆下單的產品，請不要任意換成藍色吹氣盒3.產品說明書及贴標圖稿一律由我司更改請不要任意自行更改圖稿\n每次出貨，请提供產品出肯照片，若有不符，我司會要求停止出貨，更正與為', NULL, 1, 1, NULL, 10.00, '', 27, 24.79, '', '', ' ', 'https://www.youtube.com/channel/UCYfY1mIAyNf6tPuSb7DyoPQ/videos/', 'https://www.linkedin.com/in/po-hsiang-chan/?originalSubdomain=uk', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (94, 101061, 'SA10035', 'OOO ENTUZIAST', 'C', 'AET', 'OOO ENTUZIAST', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-02-23 17:47:04', '2026-01-29 08:40:09', NULL, NULL, '60e7f9e3d4592a', '60e7f9e3d4592a', ' ', '111024, Москва, 1-я ул. Энтузиастов, д.12', NULL, '7 (499) 649-25-66；(495) 229 50 65；+7 (495) 135-23-37；+7 (499)444-55-31', NULL, 'https://www.entuziast.ru/;https://entuziast-spares.ru/;https://aet-auto.ru/;http://www.entuziastvsk.ru/', 1, '0', 0, 309524, 127238, NULL, 234.00, NULL, 100070, '168254', ' ', '', '', 'Enthusiast 公司是俄罗斯最大的电动工具和设备供应商和制造商之一。该公司在俄罗斯联邦几乎所有地区都拥有广泛的经销商网络。今天，爱好者是世界知名电动工具和设备制造商的官方经销商，如博世、牧田、美泰保、日立、得伟、百得、Skil、Remeza等。Enthusiast 备件商店包含超过 100 万个用于各种用途和特性的电动工具、机械和设备的备件。ENTUZIAST 商店是 Entuziast 集团公司的主要零售部门，在俄罗斯乐器市场拥有超过 25 年的经验。\n\n\n\nGK Entuziast拥有多个知名品牌，例如：\n\n\n\n阿森纳 - 终身保修的手动工具\n\n车库 - DIY 市场的压缩机和喷漆设备\n\nAttack - 电动和气动工具的消耗品和配件\n\nProfteplo - 电力、燃气和柴油热发生器\n\nProfmash - 混凝土搅拌机和喷枪\n\nAE&T——汽车服务设备\n\nARMADA——汽车服务设备\n\n并且还是俄罗斯以下品牌设备的主要经销商：\n\n\n\nRemeza - 压缩机设备\n\nGAV——压缩空气配件\n\nSUMAKE 是一款专业的工业气动工具。\n\nAE&T——汽车服务设备\n\nARMADA——汽车服务设备', '电动工具、量具、压缩机和涂装设备、汽车服务和洗车设备、气动工具、园林设备耗材、工具消耗品、手工具、园艺设备、园艺工具和浇水、焊接设备、机械工具、建筑及高层设备、加热设备、家庭用品、电源', NULL, NULL, NULL, '1', 0, '装柜的话：\n\n1，集装箱外面要拍，空箱里面也要拍  \n\n2，装了1/4,1/2,3/4，装完都要拍如照片。\n\n锁柜的话：如果右门左把手有孔就锁在右门左把手上，没孔也可以锁下面，总之照片多拍几张。\n\n不要破的集装箱\n\n3,每款产品发货必须要整箱，不能有零数箱。\n\n4，装箱数必须和唛头一样，不能更改。\n\n5，唛头四面贴', '2', '', '注意出货照要求：正唛，侧唛，产品装在箱子里面的照片.单个产品称重的照片，一箱货称重的照片，单个产品热收缩的照片 产品细节照片 跟整个塑盒加产品的照片', NULL, 2, 1, NULL, 10.00, '', 0, 9.64, '', '', ' ', 'https://www.youtube.com/channel/UCG6T2aBgZ-Pb4ZDJl3nw5Cw?view_as=subscriber', '', 'https://www.facebook.com/groups/entuziastspares；https://www.facebook.com/people/%D0%9E%D0%B1%D0%BE%D1%80%D1%83%D0%B4%D0%BE%D0%B2%D0%B0%D0%BD%D0%B8%D0%B5-%D0%90%D1%82%D0%BB%D0%B0%D0%BD%D1%82%D0%B0/100026683748989', '', '', 'https://vk.com/entuziast_spares；https://vk.com/aetauto', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (95, 101062, 'RO003', 'UAB Autoiranga', 'C', 'UAB', 'UAB Autoiranga', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 238073, '罗元标', 100098, 0, '2021-02-23 17:47:04', '2026-01-28 18:41:48', NULL, NULL, '6163dfa688fc44', '6163dfa688fc44', ' ', 'Veiverių 183D, Kaunas', NULL, '+370 699 68 501；+370 699 68 501；+370 37 42 02 77；', NULL, 'http://www.autoiranga.lt/', 7, '0', 0, 0, 127177, NULL, 234.00, NULL, 100070, '168250', ' ', '', '', '我们的合作伙伴是世界和欧洲知名的汽车维修设备和材料制造商：AMI AUTOMOTIVE INDUSTRIAL、UNITROL、SICAM、OMA、LICOTA、NUSSBAUM、BLITZ、BEST PATCH、DELTA PIW、RODCRAFT等。公司于1997年12月15日代表UAB AMANDA IR KO成立。', '汽车升降机\n\n车轮安装机\n\n车轮平衡机\n\n手动工具 Licota\n\n手工具 其他\n\n其他设备\n\n液压设备\n\n气动工具\n\n压缩机\n\n润滑设备\n\n诊断设备\n\n坑式升降机\n\n涂装室\n\n车轮几何装配架\n\n排气系统\n\n轮胎和内胎补丁\n\n重量\n\n阀门\n\n车身修复设备\n\n焊接设备\n\n夹子\n\n专用工具\n\n自化\n\n挖掘机', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, 1, NULL, 3.00, '', 0, 20.38, '', '', ' ', 'https://www.youtube.com/channel/UCEFQYjGIN5MePqfDsT0FA4g', '', 'https://www.facebook.com/Autoiranga-265069180218042/', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (96, 101063, 'RO026', 'BGS technic KG', 'C', 'BGS', 'BGS technic KG', ' ', 1, 100024, '2026-01-29 00:00:00', '100049', 100049, 238073, '罗元标', 100098, 0, '2021-02-23 17:47:04', '2026-01-29 08:41:03', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', 'Bandwirkerstr. 3 42929 Wermelskirchen Germany', NULL, '+49 (0) 2196-720480', NULL, 'www.bgstechnic.com', 7, '0', 0, 309524, 127180, NULL, 234.00, NULL, 100069, '168251', ' ', '', '', '自1970年开始生产以来，BGS technic◎品牌在德国和其他80多个国家以其卓越的品质和众多创新创新而闻名，并在客户中享有盛菩。在我们的产品系列中，您会发现用于日常车间和工业用途的高品质、耐用的手动、压缩空气和电动工具。为了客户的利益，我们的首要目标是以尽可能高的性价比和快速的服务提供所有产品。超过8,000种质量工具和每月的范围扩展以卓越的专业质量提供。所有产品均直接从我们现代化的中央物流设施以精美的德语和英语包装供应。自1970年开始生产以来，BGS technic◎品牌在德国和其他80多个国家以其卓越的品质和众多创新创新而闻名，并在客户中享有盛菩。在我们的产品系列中，您会发现用于日常车间和工业用途的高品质、耐用的手动、压缩空气和电动工具。为了客户的利益，我们的首要目标是以尽可能高的性价比和快速的服务提供所有产品。超过8,000种质量工具和每月的范围扩展以卓越的专业质量提供。所有产品均直接从我们现代化的中央物流设施以精美的德语和英语包装供应。到2021年，我们将把Kraftmann和Bergland 品牌合并到BGS Do it yourself》品牌下。这将使我们能够利用我们数十年的专业知识，以极具吸引力的性价比提供超过1,000种车间、DIY和家居和花园用品-像往常一样经过质量测试并提供全面的BGS支持.BGS Do it', '电动/无绳电池工具 气动工具 高压工具/绝缘工具 手工具 扭力工具 钻头套筒和钻头 套筒套件和工具分类 棘轮、延长件、适配器 汽车专用工具 车间工具 工具车 汽车配件 工业安全 工业化学品', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, 1, NULL, 3.00, '', 29, 18.41, '', '', ' ', 'https://www.youtube.com/channel/UCIjbxYDrpBtWAPpsJ3JeelQ', 'https://www.linkedin.com/company/bgs-technic-kg/about/', 'https://www.facebook.com/BGS.technic/photos/?tab=album&album_id=1649381908420279', '', 'https://www.instagram.com/bgstechnic/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
