INSERT INTO `bd_customer` VALUES (106, 101073, 'SA0001', 'KIMCO INDUSTRIAL CO., LTD.', 'C', '立华国际', 'KIMCO INDUSTRIAL CO., LTD.', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '冯序', 100085, 0, '2021-02-23 17:47:04', '2026-01-29 08:40:09', NULL, NULL, '60e7ec98d457d9', '60e7ec98d457d9', ' ', '5F，201号，台湾台北市南京东路三段。；上海市闵行区中春路7319号 莎海商务大厦5楼B座', NULL, '886-2-27180298', NULL, 'http://www.tranzac.com.tw/', 7, '0', 0, 309585, 127219, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', 'Tranzac Corporation 成立于 1988 年，专门为台湾和中国的各个市场提供广泛的汽车零部件。\n\n\n\n我们拥有一支在汽车零部件行业拥有超过 20 年经验的团队，与海外客户建立了长期的合作关系。\n\n我们在中国上海的办公室展示了 10,000 多种零件', '- 悬挂零件- 气缸盖- 泵：油泵、水泵、燃油泵- 发动机轴承- 活塞、活塞环- 凸轮轴、曲轴- 计时套件、计时组件- 刹车盘、刹车片- 转向架和靴子- 风扇皮带，正时皮带- 滤清器：机油滤清器、燃油滤清器、空气滤清器- 等速万向节- 垫片- 化油器- 发动机阀门', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 3.00, '', 2, 29.58, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (107, 101074, 'VI0006', 'CARMAX S C GRZEGORZ STAŃCZAK ANNA LEWSZYK STAŃCZAK', 'C', 'Gref', 'CARMAX S C GRZEGORZ STAŃCZAK ANNA LEWSZYK STAŃCZAK', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100952, '', 100099, 0, '2021-02-23 17:47:04', '2026-01-28 18:41:48', NULL, NULL, '60e7d9f3d454c8', '60e7d9f3d454c8', ' ', 'UL. POSWIęCKA 55 51-128 WROCLAW，POLAND', NULL, '505 727 777', NULL, 'http://carmax24.pl/', 1, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168244', ' ', '', '线上销售', '', '弯管器，气动冲击扳手，钣金工具，手动工具，喷砂机，举升机，拉马，弹簧压缩器，诊断仪，工具套装等', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 12.76, '', '', ' ', '', '', 'https://www.facebook.com/permalink.php?story_fbid=2830305803732336&id=155644714531805', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (108, 101075, 'VI0026', 'ISW Trading Pty. Ltd.', 'C', 'ISW', 'ISW Trading Pty. Ltd.', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100952, '', 100099, 0, '2021-02-23 17:47:05', '2026-01-29 08:40:09', NULL, NULL, '60e7ba25d450c8', '60e7ba25d450c8', ' ', '41 Yarraman Place, Virginia, Queensland. 4014 Australia', NULL, ' ', NULL, 'https://www.iswtrading.com/', 7, '0', 0, 309265, 127290, NULL, 234.00, NULL, 100070, '168250', ' ', '', '线上销售', '', '汽配，品牌代销', NULL, NULL, NULL, '1', 0, '1.限重要求，一个外箱不能超过16公斤\n\n2.纸箱要求：常规现在是5层 \n\n3.打托（塑料托盘）\n\n塑盒一套一箱装的，塑盒凹槽上面要彩贴，五层瓦楞箱上需要唛头+外箱彩贴都需要，如果产品太小搬运不方便 需要加外箱，那么外箱也是需要+外箱彩贴和唛头的；白盒和插卡包装的产品，产品的彩贴直接贴在插卡或者白盒上面，然后装进五层瓦楞纸的外箱里面，外箱唛头+外箱彩贴正常贴在外箱', '2', '', ' ', NULL, 1, 1, NULL, 10.00, '', 2, 19.76, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
