INSERT INTO `bd_customer` VALUES (110, 101077, 'VI0041', 'SEB', 'C', 'SEB', 'Mundo Herramientas', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100952, '', 100099, 0, '2021-02-23 17:47:05', '2026-01-28 18:41:48', NULL, NULL, '60ec09608914ea', '60ec09608914ea', ' ', 'Calle San Antonio 1395, esquina 15 Norte Viña del Mar', NULL, ' ', NULL, 'https://mundoherramientas.cl/', 7, '0', 0, 0, 151418, NULL, 234.00, NULL, 100070, '168254', ' ', '', '线上销售', '', '电动，气动工具，工具柜，油滤等', NULL, NULL, NULL, '1', 0, '一、包装需要定牌彩贴 我们这边没有的要尽快给出彩贴尺寸，客户会及时帮我们做彩贴设计\n\n二、一个外箱不能超过20公斤,\n\n三、纸箱要求：常规现在是5层，禁止有破损，工字型封箱\n\n四、下单是看下相关产品的具体参数，不懂的问业务，谢谢\n\n五、之前客户的投诉配件记得跟这个订单一起发货，谢谢\n\n六、老客户如果换供应商要提供给我所有的对比图，如若不提供对比图，出现任何问题业务概不负责 采购全责。\n\nF1029 插卡背面有中文字下单注意，要订订书针。', '2', '', '打托发货  可出口塑料托', NULL, 2, 1, NULL, 10.00, '', 41, 17.78, '', '', ' ', 'https://www.youtube.com/channel/UC0QTC78LadwveiyxlfKWoFQ', '', 'https://www.facebook.com/mundoherramientas.cl/', '', 'https://www.instagram.com/mundoherramientas.cl/', '', '', 'import@mundoherramientas.cl', '+56996152763', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (111, 101078, 'VI0046', 'E MCINTYRE AND SONS LIMITED', 'C', 'JPT', 'McIntyre’s Tools & Equipment', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100952, '', 100099, 0, '2021-02-23 17:47:05', '2026-01-28 18:41:48', NULL, NULL, '60e7bb69d450ee', '60e7bb69d450ee', ' ', '14 Drumagarner Road, Kilrea, N. Ireland, BT51 5TB', NULL, ' ', NULL, 'https://www.emcintyre.com/\n\nhttps://jeffersontools.com/about', 1, '0', 0, 0, 127301, NULL, 234.00, NULL, 100070, '168250', ' ', '', '线下实体店（品牌代理和自我品牌）', '属于家族企业在英国 有3家实体店铺分别设置在基尔雷亚、邓甘农和贝尔法斯特，主要的市场是北爱尔兰市场', '电动工具，气动工具、接入设备、手动工具、焊接设备、工作服和安全、压力清洗、电动工具、发电机、加热等等', NULL, NULL, NULL, '1', 0, '一、质量要跟之前一样，只能变好不能变差\n\n二、限重要求，一个外箱不能超过20公斤\n\n三、纸箱要求：常规现在是5层，特殊要求要注明。\n\n四、外箱胶带打包工字型', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 18.22, '', '', ' ', '', '', '', '', 'https://www.instagram.com/mcintyrestools/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
