INSERT INTO `bd_customer` VALUES (118, 101085, 'AL007', 'DELO TECHNIKI LTD', 'C', 'DELO', 'DELO TECHNIKI LTD', ' ', 1, 100024, '2026-01-29 00:00:00', '100049', 100049, 229982, '冯序', 100098, 0, '2021-02-23 17:47:05', '2026-01-29 08:42:58', NULL, NULL, '60e7f9e3d4592a', '60e7f9e3d4592a', ' ', 'Моcковская область, Ленинский район, п. Горки Ленинские, Технопарк М4, улица Западная, владение 32', NULL, '+7 (495) 181-61-31, +7 (495) 758-07-11', NULL, 'https://www.delot.ru/', 1, '0', 0, 309585, 127115, NULL, 234.00, NULL, 100068, '185914', ' ', '', '', 'Delo Tekhniki 是一家俄罗斯手工工具制造商。自 1994 年以来，该公司在俄罗斯工具市场积累了丰富的交易经验。公司拥有自己的实验室，配备了现代化的设备，在此基础上进行额外的产品质量控制。', '工具包、量具、切割用具、打击乐器、钳子、扳手、液压工具、螺丝刀、套筒', NULL, NULL, NULL, '1', 0, '唛头要求：标准出口双瓦楞A级纸箱包装，工字型胶带封口。每箱装箱数据与实际相差不得超过0.5.', '2', '', '', NULL, NULL, 1, NULL, 3.00, '', 64, 23.65, '', '29a6657bf99445258939c2ce631fb83d', ' ', 'https://www.youtube.com/channel/UCTXz4vFbX4tllTMwslL-uDw', '', '', '', 'https://www.instagram.com/delot_ru/', 'https://vk.com/club68844440', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (119, 101086, 'AL011', 'SATRA CORPORATION', 'C', '瑞祥工具有限公司', '瑞祥工具有限公司', ' ', 1, 100024, '2026-01-29 00:00:00', '100049', 100049, 275756, '冯序、李巧玲、唐雨萌', 100098, 0, '2021-02-23 17:47:05', '2026-01-29 08:41:03', NULL, NULL, '60e7d9f3d454c8', '60e7d9f3d454c8', ' ', '台北市信義區基隆路二段48號7樓之2 （編號53761990）', NULL, ' ', NULL, 'www.astatools.tw/', 7, '0', 0, 309585, 151999, NULL, 234.00, NULL, 100069, '168251', ' ', '', '品牌商/贸易商', 'over 200分包商位于日本、台湾、波兰和中国', '手工具，汽修工具，气动工具，焊机', NULL, NULL, NULL, '1', 0, '外箱贴我司提供的条码', '2', '', ':出货照需求\n(每一個產品都需要)\n1.完整產品照(無包裝)\n2.細部鐳射照(可以看清楚鐳射樣式)\n3.包装完整產品照\n4.標貼、條碼貼、說明書\n5.外箱正、惻嘜以及外箱條碼貼\n另外如果是新產品需要提供背景乾淨的產品照(可提供多角度)我們需要放到目錄以及網站上\n出貨照請出貨前提供給我確認，也不要太晚提供，因為需要時間核對謝謝', NULL, 1, 1, NULL, 3.00, '', 9, 11.87, '', '', ' ', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (120, 101087, 'AL009', 'RYCO Group Pty Ltd', 'C', 'GUD', 'RYCO Group Pty Ltd', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 238073, '冯序', 100098, 0, '2021-02-23 17:47:05', '2026-01-29 08:45:23', NULL, NULL, '60e7ba25d450c8', '60e7ba25d450c8', ' ', '29 Taras Ave, Altona North VIC 3025澳大利亚', NULL, '1800 804 541', NULL, 'http://rycofilters.com.au/', 7, '0', 0, 309585, 127117, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', 'RYCO 品牌名称从此成为澳大利亚汽车售后市场的标志。60 年来，RYCO 一直是澳大利亚最畅销的汽车机油、空气和燃油滤清器品牌，其质量范围和质量水平引领澳大利亚市场。Ryco 拥有最全面的车辆过滤器和专业过滤器程序。我们的过滤器符合或超过 OE 规格，您可以保护您所维修车辆的法定新车保修。我们拥有全面的分销网络，因此您可以随时随地获得 Ryco。', '机油滤清器、空气过滤器、油水分离器、燃油滤清器、冷却液过滤器、尿素过滤器、过滤器清洁工具、', NULL, NULL, NULL, '1', 0, '唛头要求：标准出口双瓦楞A级纸箱包装，工字型胶带封口。每箱装箱数据与实际相差不得超过0.5.\n\n定牌插卡，激光打字LOGO+日期,LOGO高度5MM+三点钟方向箭头', '2', '', '', NULL, NULL, 1, NULL, 3.00, '', 7, 33.37, '', '5f39f4d990be4b0aacb97d0015a9dccd', ' ', 'https://www.youtube.com/channel/UC8HQNM_vRLCW9r59KsX57Mg?view_as=subscriber', 'https://www.linkedin.com/company/ryco-group/about/', 'https://www.facebook.com/rycofilters/', 'https://twitter.com/ryco_filters', 'https://www.instagram.com/rycofilters/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
