INSERT INTO `bd_customer` VALUES (134, 118364, 'SA055', 'ProGlass GmbH', 'C', 'PGG', 'ProGlass GmbH', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-04-06 10:17:44', '2026-01-28 18:41:48', NULL, NULL, '61161d2928d9a0', '61161d2928d9a0', ' ', 'Michael-Becker-Str. 2 73235 Weilheim an der Teck Germany', NULL, '0 70 23/9 00 13-0', NULL, 'https://www.proglass.de/', 7, '0', 0, 0, 127229, NULL, 234.00, NULL, 100070, '168254', '673cb7c55ea24626ae639ff2ec5adf0e', '', '', '我们的产品系列始终针对汽车玻璃加工公司。无论是独立车间、品牌车间、汽车玻璃厂还是汽车、卡车、公共汽车和轨道车辆的制造商。我们的产品已成功应用于所有这些领域。\n\n\n\n由于我们的产品范围广泛，我们可以为每位客户提供满足其要求的最佳工具。除了库存充足的用于切割车窗的手动工具外，我们还拥有市场上几乎所有的电动和气动车窗切割设备。', '线切割技术\n\n拉刀切割技术\n\n工具（电动和气动）\n\n拆装工具\n\n刮刀和其他切割工具\n\n校准\n\n传感器技术\n\n窗格组件\n\n胶带、粘合剂和通用型材\n\nICOR产品\n\n用于安装橡胶盘的工具\n\n其他辅助工具\n\n工具分类和组织系统\n\n玻璃的运输和储存\n\n夹层玻璃修复和玻璃划痕去除\n\n大灯准备\n\n车辆保护和个人防护装备\n\n清洁、保养和密封\n\n宣传材料', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 22.13, '', '', ' ', 'https://www.youtube.com/user/ProGlassDotDE', 'https://www.linkedin.com/company/proglass-germany/', 'https://www.facebook.com/proglass.de/', '', 'https://www.instagram.com/proglassgmbh/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
