INSERT INTO `bd_customer` VALUES (136, 118425, 'ST285', 'KW automotive GmbH', 'C', 'KWAG', 'KW automotive GmbH', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100949, '石云涛', 100100, 0, '2021-04-06 13:05:39', '2026-01-28 18:41:48', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', 'Aspachweg 14\n\nD- 74427 Fichtenberg, Germany', NULL, ' ', NULL, 'https://www.kwsuspensions.net/', 7, '0', 0, 0, 127265, NULL, 234.00, NULL, 100070, '168250', '673cb7c55ea24626ae639ff2ec5adf0e', '', '线上与批发，经销商', '', '汽车的悬架系统', NULL, NULL, NULL, '1', 0, '需要打托，会有托盘的唛头，出货前业务会去随机检查产品质量', '2', '', '', NULL, 2, 1, NULL, 3.00, '', 0, 30.40, '底盘制造，始于1995年\n\n450 名员工，其中 330 名在 Fichtenberg（德国）的主要工厂\n\n在美国、中国、台湾、日本、英国和瑞士的国际子公司\n\n70多个国家的销售合作伙伴\n\n个性化悬架解决方案的开发、生产和销售\n\n专注于避震器、房车赛车悬架和 GT Sport\n\n电子减震器和驾驶动态控制系统的开发和调整\n\n经典悬架、液压提升系统、高度可调的弹簧组、车轮垫片\n\n拥有超过 26,000 种避震应用的最大售后悬架产品组合', '', ' ', 'https://www.youtube.com/user/KWgewindefahrwerke', '', 'https://www.facebook.com/KWsuspensionsINT/?brand_redir=182918435096079', 'https://twitter.com/KWautomotive', 'https://www.instagram.com/kw_suspension/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (137, 118426, 'RO044', 'panorama24', 'C', 'MAS', 'panorama24', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 238073, '罗元标', 100098, 0, '2021-04-06 13:06:20', '2026-01-28 18:41:48', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', 'Chromstraße 4, 30916 Isernhagen', NULL, '+49 511 21241670', NULL, 'https://panorama24.eu/', 1, '0', 0, 0, 127182, NULL, 234.00, NULL, 100070, '168246', '673cb7c55ea24626ae639ff2ec5adf0e', '', '', '我们有多种尺寸和组件的库存，因此可以保证在收到付款后仅 2 天的快速交货时间。许多品牌制造商如 Winkhaus、Aluplast、Gealan 和 VEKA 也出现在我们的窗型材中。我们以批发条款为业余工匠和专业手工艺企业提供经过测试的最高质量工具', '五金工具，工作服，货架，手动工具，纸板箱，气床，电视支架', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, 1, NULL, 3.00, '', 0, 5.01, '', '', ' ', '', 'https://www.linkedin.com/company/panorama24-gmbh/', '', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (138, 118427, 'RO390', 'DAC TIN EQUIPMENT TECHNOLOGY COMPANY LTD', 'C', 'THIE', 'datet', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 229982, '罗元标', 100098, 0, '2021-04-06 13:07:04', '2026-01-29 08:40:09', NULL, NULL, '60e7e566d45700', '60e7e566d45700', ' ', 'SR: 630/8 QL13, P. Hiệp Bình Phước, Q. Thủ Đức, TP. HCM', NULL, '0984.536.625；028.3620.9792', NULL, 'http://thietbiotodactin.com/vi/index.html；https://datet.vn/', 1, '0', 0, 309261, 127190, NULL, 234.00, NULL, 100070, '168246', '673cb7c55ea24626ae639ff2ec5adf0e', '', '', 'DUC TIN提供的产品均来自世界知名品牌，品质得到全球客户的认可，并提供最好的保修和售后服务。\n\n\n\n- DAC TIN在汽车设备技术和汽车工程技术领域拥有一支高素质的技术人员队伍。DAC TIN专业提供汽车维修保养设备、检测设备、洗车设备、清洁润滑设备、职业培训设备、手动工具...... DUC TIN为整个投标包进行机械的建造、供应和安装或根据每个客户投资项目的要求提供服务：咨询、设计、设备供应、安装订购技术转让、维修、保修和长期维护根据国际标准 ISO 9001:2000 和国际环境标准 ISO 14001:2004 的质量管理体系提供服务。', '拓普工具 工具信野 起重设备 轮胎设备-车轮 车身修复设备 合涂设备 清洁工具 润滑设备 液压设备 气动设备发动机维修设备 检测设备 空调设备 教学模式 工具柜和手推车 电池设备 机械的ROTAKE . 螺栓枪\n\n摩托车装备 安普工具 博世工具 DNT . 工具 诊断机', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, 1, NULL, 3.00, '', 0, 28.80, '', '', ' ', 'https://www.youtube.com/watch?v=hiby2quGuwk&list=PLfzICgp63O45mjJ7IbPJuUaJgqWNuG9Bg', '', 'https://www.facebook.com/Thanhvx.datet/?pnref=story', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
