INSERT INTO `bd_customer` VALUES (148, 118443, 'SA10034', 'KT', 'C', 'KT', 'Krof Tools', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-04-06 13:16:38', '2026-01-29 08:40:09', NULL, NULL, '6152d79c5e8f31', '6152d79c5e8f31', ' ', ' ', NULL, ' ', NULL, ' ', 7, '0', 0, 309265, 0, NULL, 234.00, NULL, 100070, '168250', '673cb7c55ea24626ae639ff2ec5adf0e', '', '', '一个约4000平方米的展馆，完全适应存储需求，拥有更宽敞的空间和陈列室。面向汽车行业的最好的工具和车间设备能够到达葡萄牙大陆、岛屿的各个角落和欧洲。3 年后的 2008 年，公司从未踩下增长的刹车，创建了自己的品牌：KROFtools - Professional Tools，从而巩固了其在市场上的地位。+500 经销商、+2500 产品', '套筒扳手及配件\n\n位\n\n工具柜\n\n工作台和橱柜\n\n套筒扳手套装\n\n手动工具\n\n钳\n\n特定工具\n\n车身工具\n\n监管和测试\n\n引擎工具\n\n电动工具\n\n同步工具\n\n气动工具\n\n液压工具\n\n润滑工具\n\n车间设备\n\n工作服\n\n商品推销', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/channel/UCybBLz6JpCvsWcGlZp3hOXw', 'https://www.linkedin.com/company/kroftoolsprofessionaltools/?viewAsMember=true', 'https://www.facebook.com/KROFtools/', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (149, 118444, 'SA10032', 'KING TONY POLSKA', 'C', 'King Tony', 'KING TONY POLSKA', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-04-06 13:16:59', '2026-01-28 18:41:48', NULL, NULL, '60e7d9f3d454c8', '60e7d9f3d454c8', ' ', 'ul. Kolejowa 181\n\n62-052 Komorniki', NULL, '61 8108 807、61 8107 878', NULL, 'https://kingtony.com.pl/', 7, '0', 0, 0, 155626, NULL, 234.00, NULL, 100070, '168254', '673cb7c55ea24626ae639ff2ec5adf0e', '', '', 'King Tony Tools 是一系列近 6,000 种产品，专门针对汽车、工业和农业领域专业用户的需求而设计和制造。在 100 多个国家/地区拥有 30 多年的经验后，King Tony 品牌已成为主要工业公司、机械师和工程师的首选工具，他们正在寻求优质的服务、高端工具和最佳质量以及实惠的价格。', 'Lighting\n\nHammers & Striking Tools\n\nElectronic & Electrical\n\nVDE Insulated Tools\n\nScrewdrivers & L-wrenches & Bits\n\nWrenches\n\nTorque Control & Multipliers\n\nTools Storage & Tools System Sets\n\nPneumatic Tools\n\nImpact Sockets & Accessories\n\nHand Sockets & Accessories\n\nPipe Tools\n\nPliers\n\nAutomotive Tools\n\nWorkshop Tools', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 28, 19.61, '', '', ' ', 'https://www.youtube.com/user/KingTonytool', 'https://www.linkedin.com/company/kingtonytools/', 'https://www.facebook.com/kingtonypolska', 'https://twitter.com/KINGTONYTOOL', 'https://www.instagram.com/kingtonypolska/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
