INSERT INTO `bd_customer` VALUES (180, 119479, 'AL016', 'Grainger/固安捷', 'C', 'Grainger/固安捷', 'W. W.Grainger，Inc', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100023, 100952, '', 100078, 0, '2021-04-10 10:46:35', '2023-07-13 23:04:14', NULL, NULL, '', 'f98a3ac14f0b4397a332b2353f1fc66c', ' ', 'company founded in 1927 in  Chicago, Illinois, and incorporated', NULL, ' ', NULL, 'https://www.grainger.com/\n\nhttps://www.grainger.com/content/general-catal', 1, '0', 0, 0, 0, NULL, 234.00, NULL, 123833, '0', ' ', '', '连锁店', 'Grainger的子公司Zoro Tools，Inc.和网站zoro.com于2011年成立，旨在通过仅基于网络的交易模式为美国小型企业市场提供服务，而grainger.com主要为大中型客户提供服务', '馬達，照明，物料處理，緊固件，管道，工具和安全用品等產品，以及庫存管理服務和技術支持与零售商 有实体店.', NULL, NULL, NULL, '1', 0, '', ' ', '', '', NULL, NULL, NULL, NULL, 10.00, '', 0, 0.00, 'W. W.Grainger，Inc \n\n美国财富500強的工业供应公司，W.W. Grainger，Inc.（Grainger）是维护，修理和运营（MRO）用品以及其他相关产品和服务的经销商。 该公司', '', ' ', '', 'https://www.linkedin.com/company/w.w.-grainger/', 'https://www.facebook.com/grainger/', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
