INSERT INTO `bd_customer` VALUES (182, 119481, 'AL024', '深圳百令', 'C', '深圳百令', '', 'https://www.pinterest.com/wixcom/_created/', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 238073, '冯序 罗元标', 100098, 0, '2021-04-10 10:46:36', '2026-01-28 18:41:48', NULL, NULL, '46a524cf-5797-4e46-bd0a-7203fc426d9c', '46a524cf-5797-4e46-bd0a-7203fc426d9c', ' ', '上海', NULL, ' ', NULL, 'https://www.bizslink.com/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168250', ' ', '', '', 'Bizslink 旗下的电子产品零售商拥有 7000 多种产品，其中包括手机配件、个人电脑和各种电子产品。凭借其出色的消费者购物体验，它日益成为网络市场中最受欢迎和最值得信赖的顶级零售商之一。快速、免费送货、一流的客户服务获得了超过20万客户的好评和认可。Bizslink 的汽车零部件零售商从事专业\n\n\n\nOE等效的汽车零部件分销。提供车灯、电源转换器等。我们所有的产品都广泛应用于国内外汽车行业；包括美国、欧洲、日本和韩国。Bizslink 在中国、美国和欧洲的多个城市设有办事处。200000+客户好评和认可', '电子产品、运动器材、摩托车零件、汽车零件', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, NULL, NULL, 3.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/user/Wix', '', 'https://www.facebook.com/wix', 'https://twitter.com/wix', 'https://www.instagram.com/wix/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
