INSERT INTO `bd_customer` VALUES (216, 119520, 'SA10006', 'HESSELINK', 'C', 'HESSELINK', 'HESSELINK', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 100948, '', 100085, 0, '2021-04-10 10:46:41', '2026-01-28 18:41:48', NULL, NULL, '60e7dd21d455e2', '60e7dd21d455e2', ' ', 'Hohenkörbener Weg 267 48527 Nordhorn Germany', NULL, '05921-30 26 00', NULL, 'https://www.hesselink24.de/', 7, '0', 0, 0, 127235, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', '我们的 Hesselink® 品牌在国外广为人知，由 Christian Hesselink 于 2008 年创立，运送到欧盟所有国家。我们位于欧洲的中心 Grafschaft Bentheim，并与领先的运输服务提供商密切合作，现在能够在尽可能短的时间内将每笔订单交付给我们的客户。\n\n\n\n作为一家在欧洲运营的公司，我们为工业、贸易和 DIY 领域的客户提供服务。您在任何零售店都找不到“Hesselink”品牌商品，因为我们是直销公司。这意味着我们为我们生产商品并将其直接销售给最终消费者', '冲击扳手、堆叠箱/容器、弹簧张紧器、螺丝取出器、汽车专用工具、清洁用品', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, NULL, 1, NULL, 10.00, '', 0, 0.77, '', '', ' ', 'https://www.youtube.com/user/hesselink24/about', '', 'https://www.facebook.com/Hesselink-Warenhandel-118089491600962/', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
