INSERT INTO `bd_customer` VALUES (218, 119522, 'RO009', 'Greentech', 'C', 'GREEN', 'Greentech', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 238073, '罗元标', 100098, 0, '2021-04-10 10:46:41', '2026-01-28 18:41:48', NULL, NULL, '615eb9311ad692', '615eb9311ad692', ' ', 'calle Ricardo Aicardi 145 dpto 102 urb. Chama, Santiago de Surco', NULL, '(+51) (01) 5136100', NULL, 'https://www.perumarketplace.com/showroom-main/GreentechInnovations', 1, '0', 0, 0, 127178, NULL, 234.00, NULL, 100070, '168246', ' ', '', '制造商', 'Greentech 是一家以科学为基础的公司，专注于开发新技术，以减少汽油和柴油车辆对环境的影响和运营成本。EcoEvol 是目前提供给市场的技术。这些产品安装在燃料系统中，并使用纳米技术消除微生物污染物，因此车辆可以减少高达 20% 的燃料成本，减少高达 90% 的烟雾和一氧化碳排放。其研发项目由国家科学技术委员会和生产部资助。', '燃料催化剂 柴油净化器', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, NULL, NULL, NULL, 3.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/channel/UClZ5WwNuX62tyLV9dT4ALQA', 'https://www.linkedin.com/in/rodrigo-coquis-05458a62/?originalSubdomain=pe', 'https://www.facebook.com/EcoEvolTechnology', '', 'https://www.instagram.com/ecoevol/?hl=es-la', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
