INSERT INTO `bd_customer` VALUES (312, 119626, 'RO594', 'MAJESTIC EQUIPMENT & TOOLS TRADING LLC', 'C', 'WE', 'MAJESTIC EQUIPMENT & TOOLS TRADING LLC', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 151709, 101024, '', 100098, 0, '2021-04-10 10:46:49', '2024-01-16 11:52:38', NULL, NULL, '', '616e5af0f63f1f', ' ', 'Walad Al Rolla Auto Exhaust Rad & Elect Rep W Shop, 898W+6C7 - Industrial Area - Al Nahdha - Sharjah - 阿拉伯联合酋长国', NULL, '+971 52 125 4147', NULL, 'https://majesticcarscantools.com/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '0', ' ', '', '', 'Majestic W/S Equip & Tools Trading 成立于 1997 年，由 Iqbal F. Kothawala 先生赞助。公司在沙迦工业区的厂房占地5300平方英尺，总是摆满了各种设备和机械。Majestic W/S Equip & Tools Trading 拥有一个专门的工程部门，拥有一支合格且训练有素的人员团队，他们在各种机械和设备方面拥有多年的经验。因此，该公司以其在机械和设备方面的专业知识而闻名于市场。该公司在海湾合作委员会国家拥有非常强大的客户群，并且一直是科威特、巴林、沙特阿拉伯、阿曼、卡塔尔、非洲和印度次大陆等国家的设备和机械的定期供应商。', '诊断工具\n\n \n\n重型机械\n\n \n\n关键编程\n\n \n\n计时工具\n\n \n\n电动工具\n\n \n\n焊接设备', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, NULL, NULL, 10.00, '', 0, 0.00, '', '', ' ', '', '', 'https://www.facebook.com/MajesticToolsAE/', 'https://twitter.com/alramahhardware', 'https://www.instagram.com/majesticcarscantools/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
