INSERT INTO `bd_customer` VALUES (342, 119661, 'RO422', 'Madeira & Madeira, SA', 'C', 'MSH', 'Madeira & Madeira, SA', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 229982, '罗元标', 100098, 0, '2021-04-10 11:03:55', '2026-01-28 18:41:48', NULL, NULL, '6152d79c5e8f31', '6152d79c5e8f31', ' ', 'Zona Industrial da Pedrulha,, Lote 13, 3050-183 Casal Comba Mealhada, 葡萄牙', NULL, '231 200 200', NULL, 'https://mader.pt/pagina/empresa', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168250', ' ', '', '', 'Madeira & Madeira, SA 是一家位于 Mealhada（科英布拉附近）的家族企业，致力于在伊比利亚（葡萄牙和西班牙）、安哥拉、佛得角和莫桑比克市场进口和销售机械、工具和设备。Madeira & Madeira, SA 目前拥有庞大的销售团队，覆盖整个葡萄牙领土、几个西班牙省份，并定期访问安哥拉和佛得角。\n\n\n\n我们继续投资于培训我们的员工，拥有一支在我们身边工作了 20 多年的团队。新员工的引进增加了知识，有助于培养愿意面对所有挑战的年轻团队。\n\n\n\nMadeira & Madeira, SA 集团拥有大约 60 名员工，专职于各个部门，包括技术领域。一个新的自动化和计算机化仓库，总面积为 23 000 平方米，9 个装卸码头，一个办公区和一个 900 平方米的展厅。', '五金工具 手动工具 电动工具 园艺农业工具 轮胎配件 气动工具、发电机 吸尘器 引擎 电焊、液压工具、抛光机、压缩机、气泵、电池电缆充电器', NULL, NULL, NULL, '1', 0, '', '2', '', '', NULL, 1, 1, NULL, 3.00, '', 0, 17.89, '', '', ' ', 'https://www.youtube.com/MADERPortugal', 'https://www.linkedin.com/company/mader-madeira/', 'https://www.facebook.com/MaderPortugal/', '', '', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
