INSERT INTO `bd_customer` VALUES (345, 119664, 'RO458', 'JohnDowIndustries', 'C', 'JINC', 'JohnDowIndustries', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 356247, 229982, '罗元标', 100098, 0, '2021-04-10 11:03:56', '2026-01-28 18:41:48', NULL, NULL, 'f98a3ac14f0b4397a332b2353f1fc66c', 'f98a3ac14f0b4397a332b2353f1fc66c', ' ', '151 Snyder Ave.\n\nBarberton, OH 44203', NULL, '1-866-382-5057', NULL, 'https://johndow.com/', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 100070, '168244', ' ', '', '', 'JohnDow Industries 已扩展到在其三个部门内提供维修解决方案：JohnDow Industries Service Equipment、Dynamic 和 EuroVent。35 多年来，JohnDow Industries 一直为汽车售后市场提供创新、高效、高质量的维修解决方案以及卓越的服务和支持。', '服务设备\n\nEurovent 排气提取\n\n维修零件\n\n胎压监测系统\n\n刹车维修零件\n\n燃油管路和配件\n\n放油塞和垫圈\n\n车轮硬件\n\n电气硬件\n\n车轮和轮胎用品\n\n购买硬件\n\n汽车服务化学品\n\n汽车内饰保护\n\n购买工具和用品\n\n存储解决方案\n\n盒装维修零件\n\n胎压监测系统传感器\n\n胎压监测系统传感器\n\nTPMS 诊断和编程工具\n\nTPMS 入门套件\n\nTPMS 服务套件和分类\n\nTPMS 更换阀和分类\n\nTPMS 储物柜和智能手推车\n\nTPMS 服务工具\n\n轮胎气门嘴和配件\n\n油\n\n车轮\n\n电器\n\n制动\n\n燃料\n\n车身\n\n杂项', NULL, NULL, NULL, '1', 0, '', '1', '', '', NULL, 2, NULL, NULL, 8.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/user/JohnDowIndustries', 'https://www.linkedin.com/company/johndow-industries/', 'https://www.facebook.com/JohnDowIndustries', 'https://twitter.com/johndowind', 'https://www.instagram.com/johndowindustries/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
