INSERT INTO `bd_customer` VALUES (407, 123952, 'RO496', 'SKF(China) Co., Ltd', 'C', 'SKF', 'SKF(China) Co., Ltd', 'https://www.weibo.com/skfchina1912?source=blog&is_all=1', 1, 100024, '2026-01-29 00:00:00', '151709', 100034, 229982, '罗元标(样品单）', 100098, 0, '2021-04-26 17:18:10', '2025-02-08 13:32:29', NULL, NULL, '', '46a524cf-5797-4e46-bd0a-7203fc426d9c', ' ', 'No. 291 Meiyue Road, Pudong New District Free Trade Zoe, Shanghai 200131, PRC', NULL, '400 1753 699; +86 1391721 5350', NULL, 'https://www.skf.com/cn', 7, '0', 0, 0, 0, NULL, 234.00, NULL, 123833, '0', ' ', '', '', '斯凯孚于1912年进入中国市场，服务于汽车、铁路、航空、新能源、重工、机床、物流、医疗等40余个行业，现正演进为一家知识、技术和数据驱动的企业，致力于以更智能、清洁和数字化的方式，实现斯凯孚的愿景——可靠运转的世界。斯凯孚（SKF）提供与旋转轴相关的产品和整体解决方案，包括轴承、密封、润滑管理、人工智能和状态监测。这些产品和解决方案可减少摩擦和二氧化碳排放，延长设备正常运行时间，并提高设备性能。', '滚动轴承\n\n超精密轴承\n\n回转支承轴承\n\n滑动轴承\n\n磁浮轴承和系统\n\n工业密封件\n\n汽车密封件\n\n润滑管理\n\n维护产品\n\n状态监测系统\n\n动力传动解决方案\n\n测试和测量设备\n\n汽车后市场', NULL, NULL, NULL, '1', 0, ' ', '1', '', ' ', NULL, 2, 1, NULL, 8.00, '', 0, 0.00, '', '', ' ', 'https://www.youtube.com/user/SKFOfficial', 'https://www.linkedin.com/company/skf/', 'https://www.facebook.com/SKFGroup/', 'https://twitter.com/SKFgroup', 'https://www.instagram.com/skfgroup/', '', '', '', '', '', '', '', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `bd_customer` VALUES (408, 123975, 'SA123', 'OOO \'LIDERKLYUCH\' UL.', 'C', 'ABTOM', 'ABTOMTOOL', ' ', 1, 100024, '2026-01-29 00:00:00', '151709', 100049, 100948, '', 100085, 0, '2021-04-26 17:18:12', '2026-01-29 08:40:09', NULL, NULL, '60e7f9e3d4592a', '60e7f9e3d4592a', ' ', 'г. Москва , ул. Угрешская , д.35 , оф. 21', NULL, '+7 (919) 998-80-48', NULL, 'https://avtom-center.ru/', 1, '0', 0, 309524, 157824, NULL, 234.00, NULL, 100070, '168254', ' ', '', '', '在俄罗斯市场 20 年的有效工作中，我们设法将俄罗斯制造商提供的价格合理且高质量的专业汽车工具和配件结合到我们的目录中。我们为私人客户和企业工作。商店的主要工具供应商是 Avtom-2 工厂，自 1990 年以来，该工厂一直生产用于汽车维修、调整和维护的高精度工具。自 1990 年以来，我们目录中的产品已在沃罗涅日工厂 Avtom-2 使用技术和电子设备根据法定 GOST 和 TU 由高素质的专家进行检查。该目录包含 250 多种专业汽车工具、配件、汽车调校、维修和保养设备。', '工具包、插座头、套件和附件、钻头、刀片（6格纹、花键、梅花）刀片组TORX、气球扳手、扳手、撬棍、火花塞扳手（万向结、管状）钥匙套装、螺丝刀套装、钳子、发动机工具、底盘工具、制动工具、车身工具、通用工具、诊断设备、量具、千斤顶、液压设备、绞车、润滑设备、启动、油漆、电动工具、切割工具、牵引绳、货物系绳、遮阳绳、工具箱、袋、车库工具设备、五金工具、配件', NULL, NULL, NULL, '1', 0, ' ', '2', '', ' ', NULL, NULL, 1, NULL, 10.00, '', 17, 21.59, '', '', ' ', '', '', '', '', '', '', '', '', 'whatsapp://send?phone=+79199988048', '', '', 'https://t.me/Igor_avtom', '', '', 'viber://add?number=79199988048', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
